static Fl_RGB_Image image_gnome_session_logout(idata_gnome_session_logout, 128, 128, 2, 0);

Fl_Button *button_cancel=(Fl_Button *)0;

int main(int argc, char **argv) {
  Fl::scheme("oxy");    // "gtk+" and "gleam" are popular schemes
  { main_window = new Fl_Double_Window(395, 220, gettext("WM Logout"));
    main_window->align(Fl_Align(FL_ALIGN_CLIP|FL_ALIGN_INSIDE));
    { Fl_Button* o = new Fl_Button(15, 15, 190, 190, gettext("Poweroff"));
      o->color((Fl_Color)44);
      o->selection_color((Fl_Color)41);
      o->image(image_gnome_session_logout);
      o->labelsize(16);
      o->callback((Fl_Callback*)action_poweroff);
    } // Fl_Button* o
    { Fl_Group* o = new Fl_Group(230, 15, 150, 100);
      o->selection_color((Fl_Color)41);
      o->labelsize(16);
      { Fl_Button* o = new Fl_Button(230, 15, 150, 30, gettext("Logout"));
        o->color((Fl_Color)44);
        o->selection_color((Fl_Color)41);
        o->labelsize(16);
        o->callback((Fl_Callback*)action_logout);
      } // Fl_Button* o
      { Fl_Button* o = new Fl_Button(230, 50, 150, 30, gettext("Suspend"));
        o->color((Fl_Color)44);
        o->selection_color((Fl_Color)41);
        o->labelsize(16);
        o->callback((Fl_Callback*)action_suspend);
      } // Fl_Button* o
      { Fl_Button* o = new Fl_Button(230, 85, 150, 30, gettext("Reboot"));
        o->color((Fl_Color)44);
        o->selection_color((Fl_Color)41);
        o->labelsize(16);
        o->callback((Fl_Callback*)action_reboot);
      } // Fl_Button* o
      o->end();
    } // Fl_Group* o
    { button_cancel = new Fl_Button(230, 175, 150, 30, gettext("Cancel"));
      button_cancel->color((Fl_Color)44);
      button_cancel->selection_color((Fl_Color)41);
      button_cancel->labelsize(16);
      button_cancel->callback((Fl_Callback*)action_quit);
    } // Fl_Button* button_cancel
    main_window->end();
  } // Fl_Double_Window* main_window
  //Fl::focus(button_cancel);
  main_window->show(argc, argv);
  return Fl::run();
}
